import React, { useState } from "react";
import axios from "axios";
import { useNavigate } from "react-router-dom";

function LoginScreen() {
  const [isRegister, setIsRegister] = useState(false);
  const [name, setName] = useState("");
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");

  const navigate = useNavigate();

  const submitHandler = async (e) => {
    e.preventDefault();

    try {
      if (isRegister) {
        await axios.post("http://localhost:5000/api/users/register", {
          name,
          email,
          password,
        });

        alert("Registration Successful");
        setIsRegister(false);
      } else {
        const { data } = await axios.post(
          "http://localhost:5000/api/users/login",
          { email, password }
        );

        localStorage.setItem("userInfo", JSON.stringify(data));
        navigate("/products");
      }
    } catch (error) {
      alert(error.response?.data?.message || "Error occurred");
    }
  };

  return (
    <div
      style={{
        minHeight: "100vh",
        background: "#f5f5f7",
        display: "flex",
        flexDirection: "column",
        alignItems: "center",
        paddingTop: "60px",
      }}
    >
      {/* Logo */}
      <div
        style={{
          background: "#ffe5ea",
          padding: "20px",
          borderRadius: "20px",
          marginBottom: "20px",
        }}
      >
        🛒
      </div>

      <h1 style={{ margin: 0 }}>
        Welcome to{" "}
        <span style={{ color: "#ff1744" }}> Welcome to SmartCart</span>
      </h1>

      <p style={{ color: "#777", marginBottom: "30px" }}>
        Sign in to access your personalized shop
      </p>

      <form
        onSubmit={submitHandler}
        style={{
          width: "380px",
          background: "#fff",
          padding: "30px",
          borderRadius: "20px",
          boxShadow: "0 10px 30px rgba(0,0,0,0.08)",
        }}
      >
        {isRegister && (
          <>
            <label style={{ fontWeight: "600" }}>Full Name</label>
            <input
              type="text"
              placeholder="Enter your name"
              value={name}
              onChange={(e) => setName(e.target.value)}
              required
              style={inputStyle}
            />
          </>
        )}

        <label style={{ fontWeight: "600" }}>Email Address</label>
        <input
          type="email"
          placeholder="name@example.com"
          value={email}
          onChange={(e) => setEmail(e.target.value)}
          required
          style={inputStyle}
        />

        <div style={{ display: "flex", justifyContent: "space-between" }}>
          <label style={{ fontWeight: "600" }}>Password</label>
          {!isRegister && (
            <span style={{ color: "#ff1744", fontSize: "13px", cursor: "pointer" }}>
              Forgot?
            </span>
          )}
        </div>

        <input
          type="password"
          placeholder="••••••••"
          value={password}
          onChange={(e) => setPassword(e.target.value)}
          required
          style={inputStyle}
        />

        <button
          type="submit"
          style={{
            width: "100%",
            padding: "12px",
            background: "#ff1744",
            color: "#fff",
            border: "none",
            borderRadius: "30px",
            marginTop: "15px",
            fontWeight: "bold",
            cursor: "pointer",
            fontSize: "15px",
          }}
        >
          {isRegister ? "Register to SmartCart →" : "Login to SmartCart →"}
        </button>

        <p
          style={{
            marginTop: "20px",
            textAlign: "center",
            fontSize: "14px",
            color: "#555",
          }}
        >
          {isRegister ? "Already have an account?" : "New here?"}
          <span
            onClick={() => setIsRegister(!isRegister)}
            style={{
              color: "#ff1744",
              fontWeight: "bold",
              marginLeft: "5px",
              cursor: "pointer",
            }}
          >
            {isRegister ? "Login now" : "Register now"}
          </span>
        </p>
      </form>
    </div>
  );
}

const inputStyle = {
  width: "100%",
  padding: "12px",
  marginTop: "8px",
  marginBottom: "18px",
  borderRadius: "12px",
  border: "1px solid #ddd",
  outline: "none",
  fontSize: "14px",
};

export default LoginScreen;
